{"name": "github_comment_poller", "kind": "polling", "description": "Poll GitHub issue comments with since cursor to prevent duplicate triggers. Each run records the latest comment's created_at and uses it as the since filter for the next poll.", "polling_interval": "30s", "code": "
import requests
from datetime import datetime, timezone
import os

# === Configuration — customize these or set via env vars ===
REPO = os.getenv("GH_REPO", "owner/repo")                     # e.g. "myuser/myrepo"
ISSUE_NUMBER = int(os.getenv("GH_ISSUE_NUMBER", "1"))         # issue/PR number
GITHUB_TOKEN = os.getenv("GH_TOKEN")                          # optional, for private repos


def run(state: dict = None):
    """
    Poll new comments on a GitHub issue.

    Args:
        state (dict): Persisted state between polls.
            Expected keys:
              - "since" (str | None): ISO-8601 timestamp of the last seen comment.

    Returns:
        dict: {
            "new_comments": list of comment dicts (id, user, body, created_at, html_url),
            "state": updated state dict with latest "since" cursor
        }
    """
    if state is None:
        state = {}

    since = state.get("since")  # e.g. "2024-01-01T12:00:00Z"

    headers = {
        "Accept": "application/vnd.github.v3+json",
        "User-Agent": "Forgify-Poller/1.0",
    }
    if GITHUB_TOKEN:
        headers["Authorization"] = f"token {GITHUB_TOKEN}"

    url = f"https://api.github.com/repos/{REPO}/issues/{ISSUE_NUMBER}/comments"

    params = {}
    if since:
        params["since"] = since

    try:
        resp = requests.get(url, headers=headers, params=params, timeout=15)
        resp.raise_for_status()
        comments = resp.json()
    except requests.exceptions.RequestException as e:
        return {
            "error": f"GitHub API request failed: {e}",
            "new_comments": [],
            "state": state,  # keep old state, retry next poll
        }

    if not comments:
        return {
            "new_comments": [],
            "state": state,  # cursor unchanged
            "message": "No new comments since cursor."
        }

    # --- Find the latest comment's created_at as the new cursor ---
    latest_created = max(c["created_at"] for c in comments)

    new_state = {**state, "since": latest_created}

    # Parse and return structured comment data
    new_comments = [
        {
            "id": c["id"],
            "user": c["user"]["login"],
            "body": c["body"],
            "created_at": c["created_at"],
            "html_url": c["html_url"],
        }
        for c in comments
    ]

    return {
        "new_comments": new_comments,
        "state": new_state,
        "count": len(new_comments),
        "cursor": latest_created,
    }
"}

